changeSet.sql:
alter table facility_address add column temp_facility_id varchar(20);
insert into facility_address (id, line1, line2, city, postcode, county, country, temp_facility_id) select nextval('facility_address_seq'), facilities ->'facilityDetails'->'facilityAddress'->> 'line1', facilities ->'facilityDetails'->'facilityAddress'->> 'line2', facilities ->'facilityDetails'->'facilityAddress'->> 'city', facilities ->'facilityDetails'->'facilityAddress'->> 'postcode', facilities ->'facilityDetails'->'facilityAddress'->> 'county', facilities ->'facilityDetails'->'facilityAddress'->> 'country', facilities ->>'facilityId' from underlying_agreement una, jsonb_array_elements(una.data->'underlyingAgreement'->'facilities') facilities;
update facility_data set site_name = facilities ->'facilityDetails'->>'name', scheme_exit_date = closed_date, address_id = fa.id from underlying_agreement una, jsonb_array_elements(una.data->'underlyingAgreement'->'facilities') facilities, facility_address fa where facility_id = facilities ->>'facilityId' and fa.temp_facility_id = facility_id ;
alter table facility_address drop column temp_facility_id;

alter table facility_address add column temp_facility_id varchar(20);
insert into facility_address (id, line1, line2, city, postcode, county, country, temp_facility_id) select nextval('facility_address_seq'), facilities ->'facilityDetails'->'facilityAddress'->> 'line1', facilities ->'facilityDetails'->'facilityAddress'->> 'line2', facilities ->'facilityDetails'->'facilityAddress'->> 'city', facilities ->'facilityDetails'->'facilityAddress'->> 'postcode', facilities ->'facilityDetails'->'facilityAddress'->> 'county', facilities ->'facilityDetails'->'facilityAddress'->> 'country', facilities ->>'facilityId' from request r, request_action ra, jsonb_array_elements(ra.payload ->'underlyingAgreement'->'facilities') facilities where facilities ->>'status' = 'EXCLUDED' and r.id = ra.request_id and ra.type in ('UNDERLYING_AGREEMENT_VARIATION_APPLICATION_ACCEPTED') and r.status = 'APPROVED';
update facility_data set site_name = facilities ->'facilityDetails'->>'name', scheme_exit_date = closed_date, address_id = fa.id from request r, request_action ra, jsonb_array_elements(ra.payload ->'underlyingAgreement'->'facilities') facilities, facility_address fa where facility_id = facilities ->>'facilityId' and fa.temp_facility_id = facility_id and facilities ->>'status' = 'EXCLUDED' and r.id = ra.request_id and ra.type in ('UNDERLYING_AGREEMENT_VARIATION_APPLICATION_ACCEPTED') and r.status = 'APPROVED';
alter table facility_address drop column temp_facility_id;
